<?php require_once 'db.php'; $u=require_login('student'); $st=pdo()->prepare('SELECT b.*,t.table_code,p.transaction_id FROM bookings b JOIN library_tables t ON t.id=b.table_id LEFT JOIN payments p ON p.booking_id=b.id WHERE b.student_id=? ORDER BY b.created_at DESC'); $st->execute([$u['id']]); app_header('Student Dashboard'); ?>
<h1>Welcome, <?=e($u['name'])?></h1><div class="actions"><a class="btn" href="table_booking.php">Book a Table</a><a class="btn ghost" href="pending.php">View Status</a></div><section class="card"><h2>Your bookings</h2><table><tr><th>Table</th><th>Plan</th><th>Amount</th><th>Status</th><th>Txn</th><th>Active</th></tr><?php foreach($st as $b):?><tr><td><?=e($b['table_code'])?></td><td><?=e($b['duration_days'])?> days</td><td>₹<?=e($b['amount'])?></td><td><span class="status <?=e($b['status'])?>"><?=e($b['status'])?></span></td><td><?=e($b['transaction_id'])?></td><td><?=e($b['start_date'])?> - <?=e($b['expiry_date'])?></td></tr><?php endforeach;?></table></section><?php app_footer(); ?>
